import{_ as t,c as e,o as a,ag as o}from"./chunks/framework.DPDPlp3K.js";const h=JSON.parse('{"title":"gnuplot","description":"","frontmatter":{},"headers":[],"relativePath":"计算机/软件/gnuplot.md","filePath":"计算机/软件/gnuplot.md","lastUpdated":null}'),i={name:"计算机/软件/gnuplot.md"};function r(n,l,p,u,d,s){return a(),e("div",null,l[0]||(l[0]=[o('<h1 id="gnuplot" tabindex="-1">gnuplot <a class="header-anchor" href="#gnuplot" aria-label="Permalink to &quot;gnuplot&quot;">​</a></h1><ul><li>Gnuplot 是一个开源的命令行驱动型交互式绘图工具, 用于可视化数学函数和数据</li><li>被 Octave 等第三方应用程序用作绘图引擎</li><li>支持许多不同类型的 2D 和 3D 绘图</li><li>有图形窗口, 使用指令操作</li><li>支持多种不同类型输出: 输出到交互式屏幕终端, 输出到笔式绘图仪或现代打印机, 输出到多种文件格式（EPS，JPEG ，PDF，PNG…）</li><li>官网: <a href="http://www.gnuplot.info/" target="_blank" rel="noreferrer">gnuplot homepage</a></li><li>#开源 #免费 #跨平台</li></ul><h2 id="绘图脚本文件" tabindex="-1">绘图脚本文件 <a class="header-anchor" href="#绘图脚本文件" aria-label="Permalink to &quot;绘图脚本文件&quot;">​</a></h2><ul><li><p>Gnuplot的脚本文件是一种包含一系列命令的文本文件，通常以扩展名“.gp”或“.plt”结尾。</p></li><li><p>脚本文件的两种运行方式</p><ul><li><code>gnuplot plot.gp</code></li><li>先在终端输入gnuplot进去，再 <code>load &quot;plot.gp&quot;</code></li></ul></li><li><p><code>set</code> 设置一些外观</p></li><li><p><code>plot</code> 绘制图表</p></li><li><p><code>$data &lt;&lt;EOD ... EOD</code>表示数据块</p></li></ul><h2 id="教程" tabindex="-1">教程 <a class="header-anchor" href="#教程" aria-label="Permalink to &quot;教程&quot;">​</a></h2><ul><li>官方文档: <a href="http://www.gnuplot.info/docs_5.0/gnuplot.pdf" target="_blank" rel="noreferrer">gnuplot documentation</a></li><li><a href="https://blog.csdn.net/weixin_38468077/article/details/101069365" target="_blank" rel="noreferrer">超详细的gnuplot使用教程【2】-CSDN博客</a></li><li><a href="https://zhuanlan.zhihu.com/p/356438078" target="_blank" rel="noreferrer">一张图急速入门科研绘图 Gnuplot - 知乎</a></li><li>Windows版, 图形窗口&quot;Help&quot;中自带帮助手册(英文)</li></ul><h2 id="使用示例" tabindex="-1">使用示例 <a class="header-anchor" href="#使用示例" aria-label="Permalink to &quot;使用示例&quot;">​</a></h2><ul><li>使用场景 <ul><li>GROMACS的 dssp 工具输出的.dat文件, 记录了每一帧输出的每个残基所属的二级结构的符号标识</li><li>GROMACS 2019中的do_dssp工具已经废弃, 而 dssp 工具目前只能给出二级结构的数据, 而无法直接给出xpm图.</li><li>借助 <a href="https://jerkwin.github.io/gmxtools/" target="_blank" rel="noreferrer">gmxtool</a> 中的<a href="https://jerkwin.github.io/2024/01/14/dssp%E6%95%B0%E6%8D%AE%E7%BB%98%E5%9B%BE%E8%84%9A%E6%9C%ACdssp2gp/" target="_blank" rel="noreferrer">脚本工具 dssp2g</a>, 可以将.dat数据转换为gnuplot绘图脚本.gp</li><li>再使用gnuplot运行.gp脚本就可以输出二级结构演化图.</li></ul></li></ul>',8)]))}const c=t(i,[["render",r]]);export{h as __pageData,c as default};
